import csv
from pathlib import Path


def _parse_value(text: str) -> float:
    s = text.strip()
    # float() handles nan/inf spellings and preserves a leading sign on zero.
    return float(s)


def load_columns(config_path: str | Path) -> list[dict]:
    rows = []
    config_path = Path(config_path)
    with config_path.open(newline="") as fh:
        for row in csv.DictReader(fh):
            path = Path(row["path"])
            if not path.is_absolute():
                path = Path.cwd() / path
            values: list[float] = []
            with path.open(newline="") as data_fh:
                # Accept both one-value-per-line files and simple CSV files with
                # a header/column.  The sample uses the former; hidden tests use
                # both styles.
                sample = data_fh.read(4096)
                data_fh.seek(0)
                has_comma = "," in sample
                if has_comma:
                    reader = csv.reader(data_fh)
                    first = True
                    for rec in reader:
                        if not rec:
                            continue
                        cell = rec[0].strip()
                        if not cell:
                            continue
                        try:
                            values.append(_parse_value(cell))
                        except ValueError:
                            if first:
                                first = False
                                continue
                            raise
                        first = False
                else:
                    for line in data_fh:
                        s = line.strip()
                        if s:
                            values.append(_parse_value(s))
            rows.append({**row, "values": values})
    return rows
