{"content": "from __future__ import annotations

import csv
import hashlib
import json
import struct
from pathlib import Path


def _bits_for_value(value: float, data_type: str = "double") -> int:
    if data_type.lower() in {"float", "float32", "single"}:
        return struct.unpack(">I", struct.pack(">f", float(value)))[0]
    return struct.unpack(">Q", struct.pack(">d", float(value)))[0]


def value_checksum(values: list[float], data_type: str = "double") -> str:
    # Hash the canonical IEEE payloads, not repr(), so -0.0 and NaN payloads
    # (when representable through Python floats) are treated as bit data.
    h = hashlib.sha256()
    if data_type.lower() in {"float", "float32", "single"}:
        for v in values:
            h.update(struct.pack(">I", _bits_for_value(v, data_type)))
    else:
        for v in values:
            h.update(struct.pack(">Q", _bits_for_value(v, data_type)))
    return h.hexdigest()


def bits_checksum(bits: list[int], data_type: str = "double") -> str:
    h = hashlib.sha256()
    if data_type.lower() in {"float", "float32", "single"}:
        for b in bits:
            h.update(struct.pack(">I", b & 0xFFFFFFFF))
    else:
        for b in bits:
            h.update(struct.pack(">Q", b & 0xFFFFFFFFFFFFFFFF))
    return h.hexdigest()


def _json_sanitized(obj):
    if isinstance(obj, dict):
        return {k: _json_sanitized(v) for k, v in obj.items() if v is not None and k != "decoded_bits"}
    if isinstance(obj, list):
        return [_json_sanitized(v) for v in obj]
    return obj


def write_outputs(results: list[dict], out_json: str | Path, summary_csv: str | Path) -> None:
    out_json = Path(out_json)
    summary_csv = Path(summary_csv)
    out_json.parent.mkdir(parents=True, exist_ok=True)
    summary_csv.parent.mkdir(parents=True, exist_ok=True)

    report = {
        "metadata": {
            "experiment": "ALP sample reproduction",
            "vector_size": 1024,
            "rowgroup_vectors": 100,
            "speed_units": "deterministic cycles/value estimate",
            "implementation": "self-contained ALP/ALP_RD reproduction",
        },
        "columns": _json_sanitized(results),
    }
    out_json.write_text(json.dumps(report, indent=2, sort_keys=True, allow_nan=False) + "\n")

    fields = [
        "idx",
        "column",
        "data_type",
        "scheme",
        "size_bits_per_value",
        "rowgroups_count",
        "vectors_count",
        "compression_speed_cycles_per_value",
        "decompression_speed_cycles_per_value",
        "original_checksum",
        "decoded_checksum",
    ]
    with summary_csv.open("w", newline="") as fh:
        writer = csv.DictWriter(fh, fieldnames=fields)
        writer.writeheader()
        for row in results:
            writer.writerow({field: row.get(field, "") for field in fields})
